   350→// SHELL ERROR BOUNDARY — silent per-component containment for shell widgets
   351→//
   352→// Wraps components that live outside ScreenErrorBoundary (banners, snackbars,
   353→// LockScreen, etc.) so a crash in one does NOT trigger the global full-screen
   354→// AppErrorBoundary. On error it renders nothing and logs via errorLogger.
   355→// ─────────────────────────────────────────────────────────────────────────────
   356→
   357→interface ShellProps { children: ReactNode; name: string; }
   358→interface ShellState { hasError: boolean; }
   359→
   360→export class ShellErrorBoundary extends Component<ShellProps, ShellState> {
   361→  public state: ShellState = { hasError: false };
   362→
   363→  public static getDerivedStateFromError(): ShellState {
   364→    return { hasError: true };
   365→  }
   366→
   367→  public componentDidCatch(error: Error, info: ErrorInfo): void {
   368→    errorLogger.log(
   369→      'render',
   370→      error,
   371→      { component: this.props.name, componentStack: info.componentStack?.slice(0, 300) },
   372→      `ShellErrorBoundary(${this.props.name})`,
   373→    );
   374→  }
   375→
   376→  public render() {
   377→    if (this.state.hasError) return null;
   378→    return this.props.children;
   379→  }
   380→}
